# implement-ui.ps1 - RevPilot Dashboard UI Components
# Run from your revpilot/ project root: .\implement-ui.ps1
$ErrorActionPreference = "Stop"

Write-Host "`nRevPilot UI Implementation (16 files)" -ForegroundColor Cyan
Write-Host ("=" * 45) -ForegroundColor Cyan

function Write-B64File($path, $b64) {
  $dir = Split-Path $path -Parent
  if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
  $bytes = [System.Convert]::FromBase64String($b64)
  [System.IO.File]::WriteAllBytes($path, $bytes)
  Write-Host "  + $path" -ForegroundColor Green
}

